// フローにキューを保持
let queues = flow.get("queues") || {};

let msgBody = msg.payload;
let dest = msgBody.dest;

if(!queues[dest]){
    queues[dest] = [];
}
queues[dest].push(msgBody);
flow.set("queues", queues);

msg.payload = {status: "ok"};
return msg;

let queues = flow.get("queues") || {};
let party_id = msg.req.params.party_id;

let msgs = queues[party_id] || [];
// queues[party_id] = [];
// flow.set("queues", queues);

msg.payload = msgs;
return msg;

let data = msg.payload;

let rows = [];

let bc = data.bc ? data.bc.slice(0,16) + "..." : null;
let p2p = data.p2p ? data.p2p.slice(0,16) + "..." : null;

// bc がある場合
if (bc) {
    rows.push({
        round: data.round,
        src: data.src,
        dest: data.dest,
        type: "broadcast",
        data: bc
    });
}

// p2p がある場合
if (p2p) {
    rows.push({
        round: data.round,
        src: data.src,
        dest: data.dest,
        type: "p2p",
        data: p2p
    });
}

msg.payload = rows;

return msg;

let table = flow.get("table") || [];

table = table.concat(msg.payload);

if (table.length > 100) {
    table = table.slice(-100);
}

flow.set("table", table);

msg.payload = table;

return msg;

let table = msg.payload;

if (table.length === 0) return null;

// 最新イベント
let last = table[table.length - 1];

msg.payload = {
    src: last.src,
    dest: last.dest,
    type: last.type
};

return msg;

let e = msg.payload;

msg.payload = {
    nodes: [
        {id: "co_signer1", label: "co_signer1"},
        {id: "co_signer2", label: "co_signer2"},
        {id: "co_signer3", label: "co_signer3"}
    ],
    edges: [
        {
            from: e.src,
            to: e.dest,
            color: e.type === "broadcast" ? "orange" : "cyan",
            width: 4
        }
    ]
};

return msg;

