// const elliptic = require('elliptic');
// const crypto = require('crypto');
const ec = new elliptic.ec('secp256k1');

// フロー変数から署名を取り出す
const signature_r = flow.get("signature_r");
const signature_s = flow.get("signature_s");

// フロー変数から公開鍵を取り出す
const pubX = flow.get("pubX");
const pubY = flow.get("pubY");

// const originalData = "0123456789abcdef";
const originalData = flow.get("originalData");

// 2. 元データのハッシュを計算する
const msgHash = crypto.createHash('sha256').update(originalData).digest();
// const msgHash = originalData;

// 3. 署名データと公開鍵をセット
const pubKey = { x: pubX, y: pubY };
// const signature = { r: msg.payload.signature.r, s: msg.payload.signature.s };
const signature = { r: signature_r, s: signature_s };

try {
    const key = ec.keyFromPublic(pubKey, 'hex');

    // 4. 計算したハッシュを使って署名を検証
    const isValid = key.verify(msgHash, signature);

    msg.payload = {
        isValid: isValid, // これが true なら「元データ」は1文字も改ざんされていない！
        verifiedHash: msgHash.toString('hex')
        // verifiedHash: msgHash
    };
} catch (e) {
    node.error(e.message);
}

return msg;

// 1. 現在の日時をフォーマット (2026-03-28 17:00:44)
const now = new Date();
const pad = (n) => n.toString().padStart(2, '0');
const timestamp = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())} ${pad(now.getHours())}:${pad(now.getMinutes())}:${pad(now.getSeconds())}`;

const party_id = msg.payload.party_id;
const signature_r = msg.payload.signature.r;
const signature_s = msg.payload.signature.s;

// 文字列を整形
const signature = `${party_id} r: ${signature_r.substring(0, 10)}..., s: ${signature_s.substring(0, 10)}...`;

// 2. 1行分のログエントリーを作成
const logEntry = `${timestamp} ${signature}`;

// 3. フロー変数から既存のログ配列を取得（なければ空配列 []）
let logHistory = flow.get("logHistory");
if (!Array.isArray(logHistory)) {
    logHistory = [];
}

// 4. 新しいログを【末尾】に追加 (これにより昇順になる)
logHistory.push(logEntry);

// 5. 20件を超えた場合、【先頭（一番古いもの）】を削除
if (logHistory.length > 20) {
    logHistory.shift();
}

// 6. 蓄積した配列をフロー変数に保存
flow.set("logHistory", logHistory);

// 7. 表示用に改行で結合して出力
msg.payload = logHistory.join("\n");

return msg;

